import { blockId } from './flow-id.js';

const PAGE_BREAK_COMMENT_RE = /<!--\s*(page-break-before|break-before)\s*-->/i;
const REFERENCE_DEFINITION_RE = /^\s*\[[^\]]+\]:\s+\S+/;
const STANDALONE_IMAGE_RE = /^\s*!\[[^\]]*]\([^)]+\)\s*$/;

function isBlank(line) {
  return line.trim() === '';
}

function isHeading(line) {
  return /^#{1,6}\s+/.test(line.trim());
}

function isListStart(line) {
  return /^(\s*)([-*+]|\d+[.)])\s+/.test(line);
}

function isFence(line) {
  return /^(```|~~~)/.test(line.trim());
}

function isRule(line) {
  return /^([-*_])(?:\s*\1){2,}\s*$/.test(line.trim());
}

function isTableStart(lines, index) {
  const current = lines[index]?.trim() ?? '';
  const next = lines[index + 1]?.trim() ?? '';
  return current.includes('|') && /^\|?\s*:?-{3,}:?\s*(\|\s*:?-{3,}:?\s*)+\|?$/.test(next);
}

function isPageBreakComment(line) {
  return PAGE_BREAK_COMMENT_RE.test(line.trim());
}

function isReferenceDefinition(line) {
  return REFERENCE_DEFINITION_RE.test(line);
}

function splitLongParagraph(markdown, maxLength) {
  if (!maxLength || markdown.length <= maxLength) return [markdown];

  const words = markdown.split(/\s+/).filter(Boolean);
  const parts = [];
  let current = '';

  for (const word of words) {
    const next = current ? `${current} ${word}` : word;
    if (current && next.length > maxLength) {
      parts.push(current);
      current = word;
    } else {
      current = next;
    }
  }

  if (current) parts.push(current);
  return parts.length ? parts : [markdown];
}

function appendReferenceDefinitions(markdown, referenceDefinitions) {
  if (!referenceDefinitions.length) return markdown;
  return `${markdown}\n\n${referenceDefinitions.join('\n')}`;
}

function pushBlock(blocks, type, lines, breakBefore, options, referenceDefinitions) {
  const rawMarkdown = lines.join('\n').trim();
  if (!rawMarkdown) return false;

  const maxParagraphLength = Number.isFinite(options.maxParagraphLength)
    ? Math.max(0, Math.floor(options.maxParagraphLength))
    : 0;
  const parts = type === 'paragraph'
    ? splitLongParagraph(rawMarkdown, maxParagraphLength)
    : [rawMarkdown];

  for (let partIndex = 0; partIndex < parts.length; partIndex += 1) {
    const part = parts[partIndex];
    const markdown = appendReferenceDefinitions(part, referenceDefinitions);
    blocks.push({
      id: blockId(type, part, blocks.length, options.idPrefix ?? ''),
      type,
      markdown,
      breakBefore: partIndex === 0 ? breakBefore : false,
    });
  }

  return true;
}

/**
 * Convert markdown into explicit Static.Flow items.
 *
 * This is intentionally a lightweight block splitter, not a markdown parser.
 * Templates keep rendering markdown with their own renderer.
 */
export function markdownToFlowItems(markdown = '', options = {}) {
  const normalizedMarkdown = String(markdown ?? '').replace(/\r\n/g, '\n');
  const allLines = normalizedMarkdown.split('\n');
  const referenceDefinitions = [];
  const lines = [];

  for (const line of allLines) {
    if (isReferenceDefinition(line)) {
      referenceDefinitions.push(line);
    } else {
      lines.push(line);
    }
  }

  const blocks = [];
  let index = 0;
  let breakBeforeNext = false;

  while (index < lines.length) {
    if (isBlank(lines[index])) {
      index += 1;
      continue;
    }

    if (isPageBreakComment(lines[index])) {
      breakBeforeNext = true;
      index += 1;
      continue;
    }

    const start = index;
    let type = 'paragraph';

    if (isFence(lines[index])) {
      type = 'code';
      const fence = lines[index].trim().slice(0, 3);
      index += 1;
      while (index < lines.length && !lines[index].trim().startsWith(fence)) {
        index += 1;
      }
      if (index < lines.length) index += 1;
    } else if (isHeading(lines[index])) {
      type = 'heading';
      index += 1;
    } else if (isRule(lines[index])) {
      type = 'rule';
      index += 1;
    } else if (STANDALONE_IMAGE_RE.test(lines[index])) {
      type = 'image';
      index += 1;
    } else if (isTableStart(lines, index)) {
      type = 'table';
      index += 2;
      while (index < lines.length && lines[index].includes('|') && !isBlank(lines[index])) {
        index += 1;
      }
    } else if (isListStart(lines[index])) {
      type = 'list';
      index += 1;
      while (index < lines.length && !isBlank(lines[index])) {
        index += 1;
      }
    } else if (lines[index].trim().startsWith('>')) {
      type = 'quote';
      index += 1;
      while (index < lines.length && lines[index].trim().startsWith('>')) {
        index += 1;
      }
    } else {
      index += 1;
      while (
        index < lines.length &&
        !isBlank(lines[index]) &&
        !isHeading(lines[index]) &&
        !isFence(lines[index]) &&
        !isRule(lines[index]) &&
        !STANDALONE_IMAGE_RE.test(lines[index]) &&
        !isTableStart(lines, index) &&
        !isListStart(lines[index]) &&
        !lines[index].trim().startsWith('>') &&
        !isPageBreakComment(lines[index])
      ) {
        index += 1;
      }
    }

    if (pushBlock(blocks, type, lines.slice(start, index), breakBeforeNext, options, referenceDefinitions)) {
      breakBeforeNext = false;
    }
  }

  return blocks;
}
